mapper.select:
select l.id, s.name as student_name, l.leave_type, l.start_time, l.end_time, l.status, l.create_time from leave_request l left join student s on l.student_id = s.id
and s.name like concat('%', #{studentName}, '%') and l.leave_type = #{leaveType} and l.status = #{status}
order by l.id desc

select l.id, l.leave_type, l.start_time, l.end_time, l.reason, l.status, l.create_time
from leave_request l
left join student s on l.student_id = s.id

    and l.status = #{status}
    and l.student_id = #{studentId}

select l.id, l.student_id, s.name as student_name, l.leave_type, l.start_time, l.end_time, l.reason, l.create_time from leave_request l left join student s on l.student_id = s.id
and l.status = #{status}
order by l.id desc
